class Solution:
    def canConstruct(self, s: str, k: int) -> bool:
        if len(s) < k:
            return False
        char_count = {}
        for char in s:
            if char in char_count:
                char_count[char] += 1
            else:
                char_count[char] = 1
        odd_counts = 0
        for count in char_count.values():
            if count % 2 != 0:
                odd_counts += 1
        return odd_counts <= k
```
